    "/api/v1/ezviz/detector/list": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        /**
         * 获取探测器列表
         * @description **功能描述**
         *
         *     该接口用于获取设备下关联的探测器列表（需要设备支持关联探测器）
         *
         *     > 防区故障、电池欠压、无线干扰、离线几种属于故障类型。“产生”表示产生故障，“恢复”表示故障恢复。
         *
         *     **探测器类型名称**：
         *
         *     | 探测器类型        | 探测器类型名称 |
         *     | ----------------- | -------------- |
         *     | V                 | 视频设备       |
         *     | I                 | 告警输入设备   |
         *     | O                 | 告警输出设备   |
         *     | PIR               | 红外探测器     |
         *     | FIRE              | 烟感探测器     |
         *     | MAGNETOMETER      | 门磁传感器     |
         *     | GAS               | 可燃气体       |
         *     | WATERLOGGING      | 水浸           |
         *     | CALLHELP          | 紧急按钮       |
         *     | TELECONTROL       | 遥控器         |
         *     | ALERTOR           | 告警器         |
         *     | KEYBOARD          | 键盘           |
         *     | CURTAIN           | 幕帘           |
         *     | MOVE_MAGNETOMETER | 单体门磁       |
         */
        get: {
            parameters: {
                query?: {
                    /**
                     * @description 设备ID
                     * @example xxxx
                     */
                    deviceId?: string;
                };
                header?: {
                    /** @example Bearer {{access_token}} */
                    Authorization?: string;
                };
                path?: never;
                cookie?: never;
            };
            requestBody?: never;
            responses: {
                200: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        /**
                         * @example {
                         *       "code": 200,
                         *       "message": "操作成功",
                         *       "data": [
                         *         {
                         *           "detectorSerial": "123456789",
                         *           "detectorType": "pir",
                         *           "detectorState": 1,
                         *           "detectorTypeName": "红外探测器",
                         *           "location": "测试红外探测器Aa",
                         *           "zfStatus": 0,
                         *           "uvStatus": 0,
                         *           "iwcStatus": 0,
                         *           "olStatus": 1,
                         *           "atHomeEnable": 0,
                         *           "outerEnable": 1,
                         *           "sleepEnable": 0
                         *         }
                         *       ]
                         *     }
                         */
                        "application/json": {
                            /** 返回码 */
                            code: number;
                            /** 节点对象 */
                            data?: {
                                /** 在家是否使能：0-关闭，1-开启 */
                                atHomeEnable?: number;
                                /** 探测器序列号 */
                                detectorSerial?: string;
                                /** 探测器与设备是否连通：0-非联通，1-联通 */
                                detectorState?: number;
                                /** 探测器类型 */
                                detectorType?: string;
                                /** 探测器类型名称 */
                                detectorTypeName?: string;
                                /** 无线干扰：0-恢复，1-产生 */
                                iwcStatus?: number;
                                /** 探测器位置（自定义），对应修改后的名称 */
                                location?: string;
                                /** 离线：0-恢复，1-产生 */
                                olStatus?: number;
                                /** 外出是否使能：0-关闭，1-开启 */
                                outerEnable?: number;
                                /** 状睡眠模式是否使能：0-关闭，1-开启 */
                                sleepEnable?: number;
                                /** 电池欠压：0-恢复，1-产生 */
                                uvStatus?: number;
                                /** 防区故障：0-恢复，1-产生 */
                                zfStatus?: number;
                            }[];
                            /** 返回消息 */
                            message?: string;
                        };
                    };
                };
            };
        };
        put?: never;
        post?: never;
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
