    "/api/v1/ezviz/devices/queryDeviceStatus": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        /**
         * 查询设备状态
         * @description **接口描述**
         *     该接口用于查询设备的状态信息，目前仅支持萤石设备
         */
        get: {
            parameters: {
                query?: {
                    /**
                     * @description 设备号
                     * @example C01563792
                     */
                    deviceSerial?: string;
                };
                header?: {
                    /** @example Bearer {{access_token}} */
                    Authorization?: string;
                };
                path?: never;
                cookie?: never;
            };
            requestBody?: never;
            responses: {
                200: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        /**
                         * @example {
                         *       "code": 200,
                         *       "message": "操作成功",
                         *       "data": {
                         *         "privacyStatus": 0,
                         *         "pirStatus": -2,
                         *         "alarmSoundMode": -1,
                         *         "battryStatus": -1,
                         *         "lockSignal": -1,
                         *         "diskNum": 1,
                         *         "diskState": "0---------------",
                         *         "cloudType": null,
                         *         "cloudStatus": -1,
                         *         "nvrDiskNum": -2,
                         *         "nvrDiskState": "-2"
                         *       }
                         *     }
                         */
                        "application/json": {
                            code: number;
                            data: {
                                /** 告警声音模式，0：短叫，1：长叫，2：静音,3:自定义语音,-1:设备没有上报或者设备不支持该状态 */
                                alarmSoundMode: number;
                                /** 电池电量,1到100(%)，-1:设备没有上报或者设备不支持该状态 */
                                battryStatus: number;
                                /** 云存储状态: -2:设备不支持;-1: 未开通;0: 未激活;1: 激活;2: 过期 */
                                cloudStatus: number;
                                cloudType: null;
                                /** 挂载的sd硬盘数量,-1:设备没有上报或者设备不支持该状态 */
                                diskNum: number;
                                /** sd硬盘状态:0:正常;1:存储介质错;2:未格式化;3:正在格式化;返回形式:一个硬盘表示为”0———————-“,两个硬盘表示为”00———————“,以此类推;-1:设备没有上报或者设备不支持该状态 */
                                diskState: string;
                                /** 门锁和网关间的无线信号，百分比表示 差值超过10上报,-1:设备没有上报或者设备不支持该状态 */
                                lockSignal: number;
                                /** NVR上挂载的硬盘数量: -1:设备没有上报或者设备不支持;-2:未关联,类似于NVR类型的上级设备 */
                                nvrDiskNum: number;
                                /** NVR上挂载的硬盘状态:0:正常;1:存储介质错;2:未格式化;3:正在格式化;返回形式:一个硬盘表示为”0———————-“,两个硬盘表示为”00———————“,以此类推;-1:设备没有上报或者设备不支持该状态;-2:未关联,类似于NVR类型的上级设备 */
                                nvrDiskState: string;
                                /** 红外状态，1：红外启用，0：红外禁用，-1：初始值，2：不支持,-2:设备没有上报或者设备不支持该状态 */
                                pirStatus: number;
                                /** 隐私状态: 0：隐私状态关闭；1：隐私状态打开；-1：初始值；2：不支持,C1专用,-2:设备没有上报或者设备不支持该状态 */
                                privacyStatus: number;
                            };
                            message: string;
                        };
                    };
                };
            };
        };
        put?: never;
        post?: never;
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
